import{_ as e,c as t,o as r,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Быстрый старт с AI App Factory: от установки до первого приложения | agent-app-factory","description":"Узнайте, как быстро запустить AI App Factory: от установки и настройки CLI-инструмента до понимания работы 7-этапного конвейера. Освойте инициализацию проекта и начните создавать свое первое приложение. Этот раздел включает четыре ключевых урока: быстрый старт, установку и настройку, инициализацию проекта и обзор конвейера — все, что нужно для понимания сквозного автоматизированного процесса от идеи до работающего приложения.","frontmatter":{"title":"Быстрый старт с AI App Factory: от установки до первого приложения | agent-app-factory","sidebarTitle":"Начало работы","subtitle":"Начало работы","description":"Узнайте, как быстро запустить AI App Factory: от установки и настройки CLI-инструмента до понимания работы 7-этапного конвейера. Освойте инициализацию проекта и начните создавать свое первое приложение. Этот раздел включает четыре ключевых урока: быстрый старт, установку и настройку, инициализацию проекта и обзор конвейера — все, что нужно для понимания сквозного автоматизированного процесса от идеи до работающего приложения.","order":10},"headers":[],"relativePath":"ru/hyz1992/agent-app-factory/start/index.md","filePath":"ru/hyz1992/agent-app-factory/start/index.md"}'),l={name:"ru/hyz1992/agent-app-factory/start/index.md"};function o(n,a,p,s,d,c){return r(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="начало-работы" tabindex="-1">Начало работы <a class="header-anchor" href="#начало-работы" aria-label="Permalink to &quot;Начало работы&quot;">​</a></h1><p>Этот раздел поможет вам быстро освоить AI App Factory: узнать о ключевых преимуществах, установить и настроить инструменты, а также понять принцип работы 7-этапного конвейера, чтобы подготовиться к созданию первого приложения.</p><h2 id="путь-обучения" tabindex="-1">Путь обучения <a class="header-anchor" href="#путь-обучения" aria-label="Permalink to &quot;Путь обучения&quot;">​</a></h2><p>Рекомендуется изучать материалы этого раздела в следующем порядке:</p><h3 id="_1-быстрыи-старт-от-идеи-до-приложения" tabindex="-1">1. <a href="./../getting-started/">Быстрый старт: от идеи до приложения</a> <a class="header-anchor" href="#_1-быстрыи-старт-от-идеи-до-приложения" aria-label="Permalink to &quot;1. [Быстрый старт: от идеи до приложения](../getting-started/)&quot;">​</a></h3><p>Узнайте о ключевых преимуществах AI App Factory и предварительных требованиях, а также пройдите полный цикл от идеи до готового приложения на практическом примере.</p><ul><li>Поймите механизм многопользовательского взаимодействия агентов на основе контрольных точек</li><li>Изучите полный рабочий процесс 7-этапного конвейера</li><li>Освойте технику составления четкого описания продукта</li></ul><h3 id="_2-установка-и-настроика" tabindex="-1">2. <a href="./../installation/">Установка и настройка</a> <a class="header-anchor" href="#_2-установка-и-настроика" aria-label="Permalink to &quot;2. [Установка и настройка](../installation/)&quot;">​</a></h3><p>Установите CLI-инструмент глобально и настройте AI-ассистента (Claude Code/OpenCode) и связанное окружение.</p><ul><li>Установите agent-app-factory глобально через npm</li><li>Настройте Claude Code или OpenCode</li><li>Проверьте успешность установки</li></ul><h3 id="_3-инициализация-проекта-factory" tabindex="-1">3. <a href="./../init-project/">Инициализация проекта Factory</a> <a class="header-anchor" href="#_3-инициализация-проекта-factory" aria-label="Permalink to &quot;3. [Инициализация проекта Factory](../init-project/)&quot;">​</a></h3><p>Инициализируйте директорию с помощью команды <code>factory init</code>, изучите структуру создаваемого проекта и файлы конфигурации.</p><ul><li>Выполните команду инициализации проекта</li><li>Поймите структуру директорий и файлы конфигурации</li><li>Подготовьте описание идеи продукта</li></ul><h3 id="_4-обзор-7-этапного-конвеиера" tabindex="-1">4. <a href="./../pipeline-overview/">Обзор 7-этапного конвейера</a> <a class="header-anchor" href="#_4-обзор-7-этапного-конвеиера" aria-label="Permalink to &quot;4. [Обзор 7-этапного конвейера](../pipeline-overview/)&quot;">​</a></h3><p>Углубленно изучите полный процесс конвейера — от Bootstrap до Preview, включая входные и выходные данные каждого этапа и механизм контрольных точек.</p><ul><li>Поймите цели и результаты 7 этапов</li><li>Освойте механизм контрольных точек и процесс ручного подтверждения</li><li>Научитесь управлять выполнением конвейера</li></ul><h2 id="предварительные-требования" tabindex="-1">Предварительные требования <a class="header-anchor" href="#предварительные-требования" aria-label="Permalink to &quot;Предварительные требования&quot;">​</a></h2><p>Перед началом изучения этого раздела вам понадобится:</p><div class="warning custom-block"><p class="custom-block-title">Предварительные требования</p><ol><li><strong>Среда Node.js</strong>: установлен Node.js v18 или выше</li><li><strong>AI-ассистент для программирования</strong>: необходимо настроить один из следующих инструментов <ul><li><a href="https://claude.ai/code" target="_blank" rel="noreferrer">Claude Code</a> (рекомендуется) ⭐</li><li><a href="https://opencode.design/" target="_blank" rel="noreferrer">OpenCode</a> или другой AI-ассистент с поддержкой режима Agent</li></ul></li><li><strong>Базовые навыки работы с командной строкой</strong>: умение выполнять команды в терминале</li></ol></div><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>После завершения изучения этого раздела вы освоите:</p><ul><li>✅ Основные принципы работы AI App Factory</li><li>✅ Установку и настройку CLI-инструмента</li><li>✅ Инициализацию проекта и понимание его структуры</li><li>✅ Полный процесс 7-этапного конвейера</li></ul><p>Далее рекомендуется изучить раздел <strong><a href="./../../platforms/">Платформы и интеграции</a></strong>, чтобы узнать, как запускать конвейер на различных AI-ассистентах.</p>',23)])])}const f=e(l,[["render",o]]);export{u as __pageData,f as default};
